module top_module(A, B, S);input [3:0] A;
input [3:0] B;
output reg [3:0] S; // changed to reg

wire [4:0] temp_sum;

  wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign temp_sum = {_n01, _n02, _n03, _n04}; // sum of A and B

always @(*) begin
    if(temp_sum > 15) // truncate if sum is greater than 15
        S = temp_sum[3:0];
    else
        S = temp_sum[3:0];
end

endmodule
